import ray
from ray import serve
from feast import FeatureStore

# Offline: materialize features using Ray Data as compute engine
# feast materialize uses Ray under the hood when provider is set to "local" + Ray
store = FeatureStore(repo_path="./feature_repo")

@ray.remote
def compute_user_features(user_ids: list) -> dict:
    return store.get_historical_features(
        entity_df=user_ids,
        features=["user_stats:click_rate", "user_stats:session_len"]
    ).to_df().to_dict()

# Online: Ray Serve actor caches online features
@serve.deployment(num_replicas=2, ray_actor_options={"num_cpus": 0.5})
class OnlineFeatureServer:
    def __init__(self):
        self.store = FeatureStore(repo_path="./feature_repo")

    async def __call__(self, user_id: str) -> dict:
        return self.store.get_online_features(
            features=["user_stats:click_rate"],
            entity_rows=[{"user_id": user_id}]
        ).to_dict()

import ray
from ray import serve
from ray.serve.handle import DeploymentHandle
import asyncio, random

@serve.deployment
class ShadowRouter:
    def __init__(self, champion: DeploymentHandle, challenger: DeploymentHandle):
        self.champion = champion
        self.challenger = challenger

    async def __call__(self, request):
        data = await request.json()
        champion_resp, _ = await asyncio.gather(
            self.champion.predict.remote(data),
            self.challenger.predict.remote(data)  # shadow, result discarded
        )
        return champion_resp

@serve.deployment(ray_actor_options={"num_cpus": 1})
class CanaryRouter:
    def __init__(self, champion: DeploymentHandle, challenger: DeploymentHandle, canary_pct: float = 0.05):
        self.champion, self.challenger, self.pct = champion, challenger, canary_pct

    async def __call__(self, request):
        data = await request.json()
        handle = self.challenger if random.random() < self.pct else self.champion
        return await handle.predict.remote(data)
